// Verifica se a resposta da IA é válida
const content =
  $json.content ||
  ($json.message && $json.message.content) ||
  ($json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) ||
  null;

// Recupera contexto do nó Preparar Chat
const ctx = $('Preparar Chat1').first().json;

if (!content) {
  // Sem conteúdo válido — trata como erro
  return [{
    json: {
      erro: true,
      mensagem: ctx.mensagem,
      candidatosStr: ctx.candidatosStr,
      historicoFormatado: ctx.historicoFormatado,
      tentativa: ctx.tentativa,
      maxTentativas: ctx.maxTentativas
    }
  }];
}

// Sucesso — monta resposta final
const historicoAtualizado = [
  ...ctx.historicoFormatado,
  { role: 'user', content: ctx.mensagem },
  { role: 'assistant', content: content }
];

return [{ json: {
  erro: false,
  resposta: content,
  historico: historicoAtualizado
}}];

// Verifica se ainda há tentativas disponíveis
const tentativa = $json.tentativa || 1;
const maxTentativas = $json.maxTentativas || 3;

if (tentativa >= maxTentativas) {
  // Esgotou todas as tentativas
  return [{ json: {
    podetentar: false,
    tentativa,
    maxTentativas,
    mensagem: $json.mensagem,
    candidatosStr: $json.candidatosStr,
    historicoFormatado: $json.historicoFormatado
  }}];
}

// Ainda pode tentar: aguarda 5 segundos
await new Promise(resolve => setTimeout(resolve, 5000));

// Incrementa tentativa e repassa o contexto
return [{ json: {
  podetentar: true,
  tentativa: tentativa + 1,
  maxTentativas,
  mensagem: $json.mensagem,
  candidatosStr: $json.candidatosStr,
  historicoFormatado: $json.historicoFormatado
}}];

// Todas as tentativas falharam — retorna erro amigável
return [{ json: {
  resposta: null,
  erro: true,
  mensagem: 'Não foi possível obter resposta da IA após 3 tentativas. Tente novamente em instantes.',
  historico: $json.historicoFormatado || []
}}];

// Resposta de sucesso — limpa campos internos e retorna apenas o necessário
return [{ json: {
  resposta: $json.resposta,
  historico: $json.historico
}}];

const body = $json.body || $json;

const mensagem = (body.mensagem || '').trim();
const candidatos = Array.isArray(body.candidatos) ? body.candidatos : [];
const historico = Array.isArray(body.historico) ? body.historico : [];

if (!mensagem) {
  throw new Error('Campo "mensagem" é obrigatório.');
}

const candidatosStr = candidatos.length
  ? candidatos.map((c, i) =>
      `[Candidato ${i + 1}]\n` +
      `  Nome: ${c.nome_completo || 'N/A'}\n` +
      `  Telefone: ${c.telefone || 'N/A'}\n` +
      `  Cargo pretendido: ${c.cargo_pretendido || 'N/A'}\n` +
      `  Habilidades: ${c.habilidades || 'N/A'}\n` +
      `  Localização: ${c.localizacao || 'N/A'}\n` +
      `  Resumo: ${(c.experiencia_resumida || '').substring(0, 300)}`
    ).join('\n\n')
  : 'Nenhum candidato fornecido.';

const historicoFormatado = historico
  .filter(h => h.role && h.content)
  .map(h => ({ role: h.role, content: String(h.content) }));

// Inicializa contador de tentativas
return [{ json: {
  mensagem,
  candidatosStr,
  historicoFormatado,
  totalCandidatos: candidatos.length,
  tentativa: 1,
  maxTentativas: 3
}}];
